text:
&-5 {
	flex-wrap: nowrap;
	padding-right: @size-1;
	padding-right: var(--am-grid-5-paddingRight, @size-1);
	&__overHide {
		overflow: hidden;
		padding-right: 0;
		& :nth-child(5) {
			padding-right: @size-1;
			padding-right: var(--am-grid-5-paddingRight, @size-1);
		}
	}
	&__wrap {
		flex-wrap: wrap;
	}
}

&-no-extra {
  padding-left: @size-5;
  padding-left: var(--am-coupon-no-extra-spacingL, @size-5);
  border-radius: @corner-radius-lg;
  &-text {
    margin-left: 0;
  }
  .am-coupon-content-detail-more {
    padding-right: @size-20;
    padding-right: var(--am-coupon-no-extra-detail-padding, @size-20);
  }
}

&-name {
  font-size: @avatar-fontSize-3;
  font-size: var(--am-avatar-name-size, @avatar-fontSize-3);
  color: @color-text-title;
  color: var(--am-avatar-name-color, @color-text-title);
  &-lg {
    font-size: @avatar-fontSize-4;
    font-size: var(--am-avatar-name-size-lg, @avatar-fontSize-4);
  }
}

&-button-wrap {
  .amFormat(margin-top, am-message-margintop, @size-5);
  padding: 0 @size-3;
  padding: 0 var(--am-message-button-margin, @size-3);

  & .a-button {
    margin-bottom: @size-3;
    margin-bottom: var(--am-message-button-margin, @size-3);
  }
}

&-desc {
  margin-top: @avatar-desc-between-space;
  margin-top: var(--am-avatar-desc-marginT, @avatar-desc-between-space);
  font-size: @avatar-fontSize-2;
  font-size: var(--am-avatar-desc-fontSize, @avatar-fontSize-2);
  color: @color-text-subtitle;
  color: var(--am-avatar-desc-color, @color-text-subtitle);
  &-xs {
    display: none;
  }
}

&-thumb {
  width: 28px;
  height: 28px;
  margin: 2px;
  border-radius: 50%;
  text-align: center;
  line-height: 28px;
  background: var(--adm-color-text-light-solid);
  box-shadow: 0 2px 5px 0 rgba(0, 0, 0, 0.12);
  color: var(--fill-color);
  &:focus {
    outline: none;
  }
}

li[class~="cbi-tab"] {
  border-bottom: 0.18751rem solid #5e72e4;
  border-bottom: 0.18751rem solid var(--primary);
  color: #5e72e4;
  color: var(--primary);
  background-color: #e4e9ee;
  margin-bottom: 0;

  a {
    color: #5e72e4;
    color: var(--primary);
  }
}

@-webkit-keyframes fadeOutUpCenter {
  0% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
  100% {
    opacity: 0;
    transform: translateY(-45%);
    -webkit-transform: translateY(calc(-45% - 0.5px));
  }
}

@-webkit-keyframes fadeInUpCenter {
  0% {
    opacity: 0;
    transform: translateY(-40%);
    -webkit-transform: translateY(calc(-40% - 0.5px));
  }
  100% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
}

@keyframes fadeOutDownCenter {
  0% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
  100% {
    opacity: 0;
    transform: translateY(-55%);
    -webkit-transform: translateY(calc(-55% - 0.5px));
  }
}

@keyframes fadeInDownCenter {
  0% {
    opacity: 0;
    transform: translateY(-60%);
    -webkit-transform: translateY(calc(-60% - 0.5px));
  }
  100% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
}

@keyframes fadeOutUpCenter {
  0% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
  100% {
    opacity: 0;
    transform: translateY(-45%);
    -webkit-transform: translateY(calc(-45% - 0.5px));
  }
}

@keyframes fadeInUpCenter {
  0% {
    opacity: 0;
    transform: translateY(-40%);
    -webkit-transform: translateY(calc(-40% - 0.5px));
  }
  100% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
}

& + .trm-swich {
	margin-bottom: 0;
	box-shadow: var(--box-shadow);
	background: var(--theme-bg2-color, #f4f5f7);
	border-radius: 2em;
	padding: 2px;
	.transition-mixin();

	&:after {
		width: 47%;
		border: solid 3px var(--primary, #afb42b);
		border-radius: 50%;
		background: var(--theme-bg-color, #fcfcfe);
		.transition-mixin(all, 0.2s);
	}
}

@keyframes ~"@{ant-prefix}-progress-active" {
  0% {
    transform: translateX(-100%) scaleX(0);
    opacity: 0.1;
  }

  20% {
    transform: translateX(-100%) scaleX(0);
    opacity: 0.5;
  }

  100% {
    transform: translateX(0) scaleX(1);
    opacity: 0;
  }
}

@-webkit-keyframes progressbar-infinite-1 {
    0% {
        -webkit-transform: translateX(-10%) scaleX(0.1);
    }
    25% {
        -webkit-transform: translateX(30%) scaleX(0.6);
    }
    50% {
        -webkit-transform: translateX(100%) scaleX(1);
    }
    100% {
        -webkit-transform: translateX(100%) scaleX(1);
    }
}

&.speed-dial-opened {
    .floating-button {
        i {
            .transform(translate3d(-50%, -50%, 0) rotate(90deg) scale(0.5));
            opacity: 0;
        }
        i + i {
            .transform(translate3d(-50%, -50%, 0) rotate(0deg) scale(1));
            opacity: 1;
        }
    }
}

@media (width <= 1280px), (height <= 800px) {
  .tree-view {
    .project-root.project-root {
      &::before {
        height: @tab-height * 0.8;
      }

      & > .header {
        & .name {
          height: @tab-height * 0.8 + 1px;
          line-height: @tab-height * 0.8;
        }
      }
    }
  }
}

li {
  @apply leading-6;
  @apply ~'py-0.5 px-2.5';
  @apply bg-color-bg-6;

  a {
    @apply text-color-text-inverse;
  }

  &:hover {
    .box-shadow(inset 0 0 4px theme('colors.color.bg.6'));
    border-radius: 3px;
    @apply border border-solid border-color-border;
    @apply bg-color-bg-3;
  }
}

&__content {
  @apply float-left;
  @apply ~'w-1/2';
  @apply box-border;
  @apply m-0;
  @apply pt-4 pr-4 ~'pb-1.5' pl-4;

  &.is-left {
    @apply border-r border-r-color-bg-3;
  }

  .@{date-range-picker-prefix-cls}__header div {
    @apply leading-5;
    margin: 0 auto;
  }
}

&-bar-con {
  @apply absolute;
  @apply bg-color-bg-1;

  &.vertical {
    @apply ~'top-1/2';
    @apply h-7;
    @apply translate-x-0 ~'-translate-y-1/2';
  }

  &.horizontal {
    @apply ~'left-1/2';
    @apply w-7;
    @apply ~'-translate-x-1/2' translate-y-0;
  }
}

&__selected-info {
  @apply text-color-text-primary;
  @apply text-sm;
  @apply bg-color-bg-2;
  @apply ~'py-1.5' px-4;
  @apply m-0;
  @apply rounded;

  .@{dept-prefix-cls}__selected-split_line {
    @apply py-0 px-2;
    @apply text-xs;
    @apply text-color-text-disabled;
  }
}

&[x-placement^='top'] {
  @apply mb-3;

  .popper__arrow {
    @apply -bottom-1;
    @apply ~'left-1/2';
    margin-right: 3px;
    @apply border-solid;
    @apply border-b-color-bg-1;
    @apply border-l-color-bg-1;
    @apply rounded-bl-sm;
    transform: rotate(315deg);
  }
}

&[x-placement^='bottom'] {
  @apply mt-3;

  .popper__arrow {
    @apply -top-1;
    @apply ~'left-1/2';
    margin-right: 3px;
    @apply border-solid;
    @apply border-b-color-bg-1;
    @apply border-l-color-bg-1;
    @apply rounded-bl-sm;
    transform: rotate(135deg);
  }
}

&[x-placement^='left'] {
  @apply mr-3;

  .popper__arrow {
    @apply ~'top-1/2';
    @apply -right-1;
    margin-bottom: 3px;
    @apply border-solid;
    @apply border-b-color-bg-1;
    @apply border-l-color-bg-1;
    @apply rounded-bl-sm;
    transform: rotate(225deg);
  }
}

&[x-placement^='right'] {
  @apply ml-3;

  .popper__arrow {
    @apply ~'top-1/2';
    @apply -left-1;
    margin-bottom: 3px;
    @apply border-solid;
    @apply border-b-color-bg-1;
    @apply border-l-color-bg-1;
    @apply rounded-bl-sm;
    @apply rotate-45;
  }
}

@keyframes rcTriggerZoomOut {
  0% {
    transform: scale(1, 1);
    transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
    opacity: 1;
  }
  100% {
    transform: scale(0, 0);
    transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
    opacity: 0;
  }
}

@keyframes rcTriggerZoomIn {
  0% {
    transform: scale(0, 0);
    transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
    opacity: 0;
  }
  100% {
    transform: scale(1, 1);
    transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
    opacity: 1;
  }
}

&--n,
  &--ne,
  &--nw {
    & .@{self} {
      transform: translate(-50%, ~'calc(-100% - 12px)');
      top: 0;
    }
    &:before {
      right: 50%;
      top: 0;
      margin-right: -10px;
      margin-top: -13px;
      border-top-color: @arrowColor;
      filter: drop-shadow(0px 1px 0px #aaa);
    }
  }

[id^="components-grid-demo-"] {
  .ant-row > div:not(.gutter-row),
  .ant-row-flex > div:not(.gutter-row) {
    background: #00a0e9;
    padding: 16px 0;
    &:nth-child(2n+1) {
      background: fade(#00a0e9, 70%);
    }
  }

  p {
    margin: 4px 0;
    text-align: left;
  }
}
